import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import toast from 'react-hot-toast';

export default function Login() {
  const [username, setUsername] = useState('');
  const { user, login } = useAuth();
  const navigate = useNavigate();

  if (user) {
    navigate('/');
    return null;
  }

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      login(username);
      toast.success(`Bienvenue, ${username.trim()} !`);
      navigate('/');
    } catch (err) {
      toast.error(err.message || 'Erreur de connexion');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-rose-50 text-rose-900">
      <form className="w-full max-w-sm rounded-xl border border-rose-200 bg-white p-6 shadow" onSubmit={handleSubmit}>
        <h1 className="text-2xl font-bold mb-4 text-rose-700">Connexion</h1>
        <label className="block mb-2 text-sm font-medium">Utilisateur</label>
        <input
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          className="w-full rounded-lg border border-rose-300 px-3 py-2 mb-4 focus:border-rose-500 focus:outline-none"
          placeholder="Entrez votre nom"
          autoFocus
        />
        <button className="w-full btn btn-primary" type="submit">Se connecter</button>
      </form>
    </div>
  );
}
